'use client'
import { cn } from '@cascivo/core'
import type { AnchorHTMLAttributes } from 'react'
import styles from './link.module.css'

export interface LinkProps extends AnchorHTMLAttributes<HTMLAnchorElement> {
  variant?: 'standalone' | 'inline'
  size?: 'sm' | 'md' | 'lg'
  external?: boolean
}

export function Link({
  variant = 'standalone',
  size = 'md',
  external = false,
  className,
  children,
  ...props
}: LinkProps) {
  return (
    <a
      data-variant={variant}
      data-size={size}
      data-external={external || undefined}
      className={cn(styles['link'], className)}
      {...(external ? { target: '_blank', rel: 'noreferrer' } : {})}
      {...props}
    >
      {children}
    </a>
  )
}

@layer cascivo.component {
  .link {
    color: var(--cascivo-link-color, var(--cascivo-color-accent));
    cursor: pointer;
    border-radius: var(--cascivo-radius-item);
    text-underline-offset: 0.2em;
    transition: color var(--cascivo-duration-150) var(--cascivo-ease-out);

    &:hover {
      color: var(--cascivo-color-accent-hover);
    }

    &:active {
      color: var(--cascivo-color-accent-active);
    }

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
    }

    /* Standalone: own typography, underline on hover only */
    &[data-variant='standalone'] {
      font-family: var(--cascivo-font-sans);
      font-weight: var(--cascivo-font-medium);
      text-decoration: none;

      &:hover {
        text-decoration: underline;
      }

      &[data-size='sm'] {
        font-size: var(--cascivo-text-sm);
      }

      &[data-size='md'] {
        font-size: var(--cascivo-text-base);
      }

      &[data-size='lg'] {
        font-size: var(--cascivo-text-lg);
      }
    }

    /* Inline: inherits surrounding prose typography, always underlined */
    &[data-variant='inline'] {
      font: inherit;
      text-decoration: underline;
    }

    /* External indicator — alt text '' keeps it out of the accessibility tree */
    &[data-external]::after {
      content: '\2197' / '';
      font-size: 0.8em;
      margin-inline-start: var(--cascivo-space-1);
    }
  }
}
